import { Component, OnInit, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ActivatedRoute, Router } from '@angular/router';
import { AuthService } from '../../core/services/auth.service';
import { Marker, MarkerType, SitePlan } from '../../core/models';

type Mode = 'select' | 'equipment' | 'hazard';

/**
 * SiteView 2D site plan — inline SVG with an <image> background and draggable
 * markers positioned at normalized (x·W, y·H). Planners drag markers (coords
 * stay normalized 0–1 so they reload identically at any size), add markers by
 * clicking in equipment/hazard mode, and delete the selected one. The selected
 * marker is URL-addressable via `?marker=<id>`. Viewers are read-only.
 *
 * DATA CONTRACT: `plan` / `markers` are signals of mock data; the service_agent
 * stage clears them and wires ApiService.getSitePlan() + marker create/PATCH
 * (drag)/delete in ngOnInit.
 */
@Component({
  selector: 'app-siteplan',
  standalone: true,
  imports: [CommonModule],
  templateUrl: './siteplan.component.html',
  styleUrl: './siteplan.component.css',
})
export class SiteplanComponent implements OnInit {
  readonly projectId = signal<string>('');

  // Logical SVG canvas.
  readonly W = 1000;
  readonly H = 640;

  readonly plan = signal<SitePlan>({
    id: 'sp1',
    projectId: 'p1',
    imageUrl: 'https://placehold.co/1000x640/eaeef4/5c6b80?text=Site+Plan',
  });

  readonly markers = signal<Marker[]>([
    { id: 'mk1', planId: 'sp1', x: 0.22, y: 0.30, type: 'equipment', note: 'Tower crane TC-1' },
    { id: 'mk2', planId: 'sp1', x: 0.62, y: 0.24, type: 'equipment', note: 'Material laydown yard' },
    { id: 'mk3', planId: 'sp1', x: 0.44, y: 0.58, type: 'hazard', note: 'Open excavation — fall risk' },
    { id: 'mk4', planId: 'sp1', x: 0.78, y: 0.66, type: 'hazard', note: 'Overhead power lines' },
    { id: 'mk5', planId: 'sp1', x: 0.30, y: 0.74, type: 'equipment', note: 'Site office trailer' },
  ]);

  readonly mode = signal<Mode>('select');
  readonly selectedId = signal<string | null>(null);
  private dragId: string | null = null;

  readonly selected = computed<Marker | null>(() => {
    const id = this.selectedId();
    return this.markers().find((m) => m.id === id) ?? null;
  });

  readonly hazardCount = computed(() => this.markers().filter((m) => m.type === 'hazard').length);
  readonly equipCount = computed(() => this.markers().filter((m) => m.type === 'equipment').length);

  constructor(
    public auth: AuthService,
    private route: ActivatedRoute,
    private router: Router,
  ) {}

  ngOnInit(): void {
    this.route.parent?.paramMap.subscribe((p) => this.projectId.set(p.get('id') ?? ''));
    this.route.queryParamMap.subscribe((q) => this.selectedId.set(q.get('marker')));
  }

  cx(m: Marker): number { return m.x * this.W; }
  cy(m: Marker): number { return m.y * this.H; }

  setMode(mode: Mode): void {
    if (!this.auth.isPlanner()) return;
    this.mode.set(mode);
  }

  select(id: string | null): void {
    this.router.navigate([], {
      relativeTo: this.route,
      queryParams: { marker: id },
      queryParamsHandling: 'merge',
    });
  }

  // ---- Add on canvas click (planner, add mode) ----
  onCanvasClick(evt: MouseEvent): void {
    if (!this.auth.isPlanner()) return;
    const m = this.mode();
    if (m === 'select') return;
    const { x, y } = this.norm(evt);
    const id = 'mk' + (this.markers().length + 1) + '-' + Math.round(x * 100);
    const marker: Marker = { id, planId: this.plan().id, x, y, type: m as MarkerType, note: '' };
    this.markers.update((list) => [...list, marker]);
    this.select(id);
  }

  // ---- Drag existing marker (planner) ----
  onMarkerDown(evt: PointerEvent, m: Marker): void {
    evt.stopPropagation();
    this.select(m.id);
    if (!this.auth.isPlanner()) return;
    (evt.target as Element).setPointerCapture?.(evt.pointerId);
    this.dragId = m.id;
  }
  onMarkerMove(evt: PointerEvent, m: Marker): void {
    if (this.dragId !== m.id) return;
    const { x, y } = this.norm(evt);
    this.markers.update((list) => list.map((k) => (k.id === m.id ? { ...k, x, y } : k)));
  }
  onMarkerUp(m: Marker): void {
    if (this.dragId === m.id) {
      this.dragId = null;
      // service_agent: PATCH /markers/:id with the new normalized x,y here.
    }
  }

  deleteSelected(): void {
    const id = this.selectedId();
    if (!id || !this.auth.isPlanner()) return;
    this.markers.update((list) => list.filter((m) => m.id !== id));
    this.select(null);
  }

  updateNote(note: string): void {
    const id = this.selectedId();
    if (!id) return;
    this.markers.update((list) => list.map((m) => (m.id === id ? { ...m, note } : m)));
  }

  private norm(evt: MouseEvent): { x: number; y: number } {
    const target = evt.currentTarget as SVGGraphicsElement;
    const svg = (target as SVGGraphicsElement).ownerSVGElement ?? (target as unknown as SVGSVGElement);
    const pt = svg.createSVGPoint();
    pt.x = evt.clientX;
    pt.y = evt.clientY;
    const ctm = svg.getScreenCTM();
    if (!ctm) return { x: 0, y: 0 };
    const loc = pt.matrixTransform(ctm.inverse());
    return {
      x: Math.max(0, Math.min(1, loc.x / this.W)),
      y: Math.max(0, Math.min(1, loc.y / this.H)),
    };
  }
}
